 49	const streamToTableData = (stream: StreamLogData, timezone?: string): Array<LogTableData> => {
 50	  const values = stream.values;
 51	
 52	  return values.map((value) => {
 53	    const logValue = String(value[1]);
 54	    const message = isJSONObject(logValue) ? stream.stream['message'] || logValue : logValue;
 55	    const timestamp = parseFloat(String(value[0]));
 56	    const time = timestamp / 1e6;
 57	    const formattedTime = dateToFormat(time, DateFormat.Full, timezone);
 58	    const severity = parseName(stream.stream, ResourceLabel.Severity);
 59	    const namespace = parseName(stream.stream, ResourceLabel.Namespace);
 60	    const podName = parseName(stream.stream, ResourceLabel.Pod);
 61	
 62	    return {
 63	      time: formattedTime,
 64	      timestamp,
 65	      message,
 66	      severity: severityFromString(severity) ?? 'other',
 67	      data: stream.stream,
 68	      resources: parseResources(stream.stream),
 69	      namespace,
 70	      podName,
 71	      type: 'log',
 72	      // index is 0 here to match the type, but it will be recalculated when flattening the array
 73	      logIndex: 0,
